console.log(`  - DGA:       ${resultats.filter(r => r.type_destinataire === 'DGA').length}`);
console.log(`  - Baallah:   ${resultats.filter(r => r.type_destinataire === 'BAALLAH').length}`);
console.log(`  - Farhat:    ${resultats.filter(r => r.type_destinataire === 'FARHAT').length}`);
console.log('\nDétails:');
resultats.forEach(r => {
  console.log(`  ${r.type_destinataire} - ${r.destinataire_principal.nom}: ${r.statistiques.total_attestations} attestation(s)`);
});
console.log('═══════════════════════════════════════════════════\n');

return resultats.map(r => ({ json: r }));

